assignments.value:
grammar es.um.uschema.xtext.athena.Athena with org.eclipse.xtext.common.Terminals

generate athena "http://www.um.es/uschema/xtext/athena/Athena"
import "http://www.eclipse.org/emf/2002/Ecore" as ecore

AthenaSchema returns AthenaSchema:
  'Schema' id=SchemaId
  ( 'import' imports+=Import )*
  ( featureSets+=FeatureSetDecl | entities+=EntityDecl | relationships+=RelationshipDecl )*
;

SchemaId:
  name=ValidId ':' version=VersionId
;

Import:
  importedNamespace=[AthenaSchema|QualifiedImport]
;

TopLevelStructureDefiningElementDecl:
  SchemaTypeDecl | FeatureSetDecl
;

FeatureSetDecl:
  'fset' name=ValidId
  structure=StructureExpr
;

SchemaTypeDecl:
  EntityDecl | RelationshipDecl
;

EntityDecl:
  ShortEntityDecl | RegularEntityDecl
;

// We removed { } to make it consistent with common=CommonSpec?
ShortEntityDecl:
  ( root?='root' )? 'entity' name=ValidId ( '::' parents+=[SchemaTypeDecl|QualifiedEntityName] ( ',' parents+=[SchemaTypeDecl|QualifiedEntityName] )* )?
    structure=StructureExpr
;

RegularEntityDecl:
  ( root?='root' )? 'entity' name=ValidId ( '::' parents+=[SchemaTypeDecl|QualifiedEntityName] ( ',' parents+=[SchemaTypeDecl|QualifiedEntityName] )* )?
  '{'
    common=CommonSpec?
    variations+=VariationDecl+
  '}'
;

RelationshipDecl:
  ShortRelationshipDecl | RegularRelationshipDecl
;

ShortRelationshipDecl:
  'relationship' name=ValidId ( '::' parents+=[SchemaTypeDecl|QualifiedRelationshipName] ( ',' parents+=[SchemaTypeDecl|QualifiedRelationshipName] )* )?
    structure=StructureExpr
;

RegularRelationshipDecl:
  'relationship' name=ValidId ( '::' parents+=[SchemaTypeDecl|QualifiedRelationshipName] ( ',' parents+=[SchemaTypeDecl|QualifiedRelationshipName] )* )?
  '{'
    common=CommonSpec?
    variations+=VariationDecl+
  '}'
;

CommonSpec:
  'common' structure=StructureExpr
;

VariationDecl:
  'variation' name=VariationIdSpec
  structure=StructureExpr?
;

StructureExpr returns StructureExpr:
  StructureTerm ( {StructureExpr.left=current} operator=( 'U' | '+' | '-' ) right=StructureTerm )*
;

StructureTerm returns StructureExpr:
  StructurePrimary ( {StructureTerm.left=current} operator='I' right=StructurePrimary )*
;

StructurePrimary returns StructureExpr:
  StructureLiteral | TopLevelStructureDefiningElementDeclRef  | VariationDeclRef | SQLStructure | '(' StructureExpr ')'
;

StructureLiteral:
  '{' spec=FeatureSet '}'
;

TopLevelStructureDefiningElementDeclRef:
  ref=[TopLevelStructureDefiningElementDecl|QualifiedTopLevelStructureDefiningElementName]
;

VariationDeclRef:
  ref=[VariationDecl|QualifiedVariationName]
;

FeatureSet: 
  features+=Feature ( ',' features+=Feature )*
;

Feature:
  ComposedReference | SimpleFeature
;

ComposedReference:
  '(' names+=ValidId ( ',' names+=ValidId )* ')' ':' target=ComposedReferenceTarget
;

SimpleFeature:
  ( key?='+' | ( ( optional?='?' )? ( unique?='!' )? ) ) name=ValidId ( ':' type=Type )?
;

Type:
  DataType | SimpleReferenceTarget | SimpleAggregateTarget | InnerStructureLiteralArray | InnerStructureLiteral
;

//////////////////////////////////////////////////////////////////////////////////////////////////
//////////////////////////////////////////////////////////////////////////////////////////////////
/////////////////TYPE HIERARCHY///////////////////////////////////////////////////////////////////

InnerStructureLiteralArray:
  '['
    structure+=InnerStructureLiteral ( ',' structure+=InnerStructureLiteral )*
  ']'
;

InnerStructureLiteral:
  '{' spec=FeatureSet '}'
;

SimpleReferenceTarget:
  'ref' '<' ref=[EntityDecl|QualifiedEntityName]
    (
      ('as' type=SinglePrimitiveType)
      |
      ('feat' (
        featuredBy+=[RelationshipDecl|QualifiedRelationshipName] |
        ( featuredBy+=[VariationDecl|QualifiedVariationName] ( ',' featuredBy+=[VariationDecl|QualifiedVariationName] )* )
        )
      )
    )?
    '>' ( multiplicity=('?'|'&'|'*'|'+') )?
;

ComposedReferenceTarget:
  'ref' '<' ref=[EntityDecl|QualifiedEntityName] '>'
;

SimpleAggregateTarget:
  'aggr' '<' ( aggr+=[SchemaTypeDecl|QualifiedEntityName] |
             ( aggr+=[VariationDecl|QualifiedVariationName] ( ',' aggr+=[VariationDecl|QualifiedVariationName] )* )) '>' ( multiplicity=('?'|'&'|'*'|'+') )?
;

DataType:
  Null | PrimitiveType | List | Set | Map | Tuple
;

Null returns Null:
  {Null}
  'Null'
;

PrimitiveType:
  SinglePrimitiveType | OptionPrimitiveType
;

OptionPrimitiveType:
  'Option' '<' options+=SinglePrimitiveType ( ',' options+=SinglePrimitiveType )* '>'
;

List returns List:
  {List}
  'List' ( '<' elementType=DataType '>' )?
;

Set returns Set:
  {Set}
  'Set' ( '<' elementType=DataType '>' )?
;

Map returns Map:
  {Map}
  'Map' ( '<' ( keyType=PrimitiveType )? ',' ( valueType=DataType )? '>' )?
;

Tuple returns Tuple:
  {Tuple}
  'Tuple' ( '<' elements+=DataType ( ',' elements+=DataType )* '>' )?
;

//////////////END TYPE HIERARCHY//////////////////////////////////////////////////////////////////
//////////////////////////////////////////////////////////////////////////////////////////////////
/////////QUALIFIED NAMES AND PRIMITIVES///////////////////////////////////////////////////////////

QualifiedImport:
  ValidId ':' VersionId
;

QualifiedTopLevelStructureDefiningElementName:
  ValidId ( ':' VersionId )? ( '.' ValidId )*
;

QualifiedEntityName:
  ValidId ( ':' VersionId )? ( '.' ValidId )*
;

QualifiedRelationshipName:
  ValidId ( ':' VersionId )? ( '.' ValidId )*
;

QualifiedVariationName:
  QualifiedTopLevelStructureDefiningElementName '.' VariationIdSpec
;

VariationIdSpec:
  INT
;

SinglePrimitiveType:
  UnrestrictedPrimitiveType | RestrictedPrimitiveType
;

RestrictedPrimitiveType:
  RangedNumber | EnumRestrictedNumber | RegexpRestrictedString | EnumRestrictedString
;

RangedNumber:
  typename=NUMBER_LITERAL '(' from=EInt '..' to=EInt ')'
;

RegexpRestrictedString:
  typename=STRING_LITERAL regexp=REGEX
;

EnumRestrictedNumber:
  typename=NUMBER_LITERAL 'in' '(' enumVals+=EInt (',' enumVals+=EInt )* ')'
;

EnumRestrictedString:
  typename=STRING_LITERAL 'in' '(' enumVals+=STRING (',' enumVals+=STRING )* ')'
;

UnrestrictedPrimitiveType:
  typename=( STRING_LITERAL | NUMBER_LITERAL | 'Boolean' | 'Bool' | 'Identifier' | 'Timestamp' )
;

NUMBER_LITERAL:
  'Integer' | 'Int' | 'Number' | 'Float' | 'Double'
;

STRING_LITERAL:
  'String'
;

EInt returns ecore::EInt:
  '-'? INT
;

VersionId returns ecore::EInt:
  INT
;

ValidId:
  ID | KEYWORD
;

KEYWORD: 'schema' | 'import' | 'struct' | 'root' | 'entity' | 'relationship' | 'common' | 'variation' | 'U' | 'I' | 'ref' | 'feat' | 'as' | 'aggr' |
         'Null' | 'Option' | 'List' | 'Set' | 'Map' | 'Tuple' | 'in' | 'Boolean' | 'Bool' | 'Identifier' | 'Timestamp' | 'Integer' | 'Int' | 'Number' |
         'Float' | 'Double' | 'String' | 'sql' | 'create' | 'temporary' | 'table' | 'if' | 'not' | 'exists' | 'constraint' | 'foreign' | 'key' |
         'references' | 'unique' | 'primary' | 'TINYINT' | 'SMALLINT' | 'DEC' | 'FIXED' | 'DECIMAL' | 'NUMERIC' | 'BIT' | 'REAL' | 'PRECISION' |
         'DATE' | 'TIME' | 'DATETIME' | 'YEAR' | 'CHAR' | 'VARCHAR' | 'BINARY' | 'VARBINARY' | 'BLOB' | 'TEXT'
;

terminal REGEX:
  '/' ( '\\' . /* 'b'|'t'|'n'|'f'|'r'|'u'|'"'|"'"|'\\'|'\/' */ | !('\\'|'/') )* '/'
;

////////END QUALIFIED NAMES AND PRIMITIVES////////////////////////////////////////////////////////
//////////////////////////////////////////////////////////////////////////////////////////////////
///////////////////SQL DDL////////////////////////////////////////////////////////////////////////

SQLStructure:
  'SQL' 'CREATE' ( 'TEMPORARY' )? 'TABLE' ( 'IF' 'NOT' 'EXISTS' )? ( name=ValidId )? '(' definitions+=SQLDefinition ( ',' definitions+=SQLDefinition )* ')' ';'
;

SQLDefinition:
  SQLColumnDefinition | SQLConstraintDefinition
;

SQLColumnDefinition:
  name=ValidId type=SQLType ( '(' EInt ( ',' EInt )? ')' )? ( constraint=SQL_CONSTRAINT_DEFINITION_LITERAL )? ( refs=SQLReferenceTarget )?
;

SQLConstraintDefinition:
  SQLPrimaryConstraintDefinition | SQLForeignConstraintDefinition | SQLUniqueConstraintDefinition
;

// Writing references here instead of colNames+=ValidId makes up for A LOT of troubles. Consider yourself warned.
SQLPrimaryConstraintDefinition:
  ( 'CONSTRAINT' ( name=ValidId )? )? 'PRIMARY' 'KEY' '(' colNames+=ValidId ( ',' colNames+=ValidId )* ')'
;

SQLForeignConstraintDefinition:
  ( 'CONSTRAINT' ( name=ValidId )? )? 'FOREIGN' 'KEY' ValidId? '(' colNames+=ValidId ( ',' colNames+=ValidId )* ')' refs=SQLReferenceTarget
;

SQLUniqueConstraintDefinition:
  ( 'CONSTRAINT' ( name=ValidId )? )? 'UNIQUE' 'KEY' ValidId? '(' colNames+=ValidId ( ',' colNames+=ValidId )* ')'
;

SQLReferenceTarget:
  'REFERENCES' ref=[EntityDecl|QualifiedEntityName] '(' colNames+=ValidId ( ',' colNames+=ValidId )* ')'
;

SQLType:
  typename=( SQL_BOOLEAN_LITERAL | SQL_NUMBER_LITERAL | SQL_DOUBLE_LITERAL | SQL_TIMESTAMP_LITERAL | SQL_STRING_LITERAL )
;

SQL_BOOLEAN_LITERAL:
  'TINYINT' | 'BOOLEAN' | 'BOOL'
;

SQL_NUMBER_LITERAL:
  'INT' | 'INTEGER' | 'SMALLINT' | 'MEDIUMINT' | 'DEC' | 'FIXED' | 'DECIMAL' | 'NUMERIC' | 'BIT'
;

SQL_DOUBLE_LITERAL:
  'FLOAT' | 'REAL' | 'DOUBLE' 'PRECISION' | 'DOUBLE'
;

SQL_TIMESTAMP_LITERAL:
  'DATE' | 'TIME' | 'DATETIME' | 'TIMESTAMP' | 'YEAR'
;

SQL_STRING_LITERAL:
  'CHAR' | 'VARCHAR' | 'BINARY' | 'VARBINARY' | 'BLOB' | 'TEXT'
;

SQL_CONSTRAINT_DEFINITION_LITERAL:
  ( SQL_PRIMARY_KEY_LITERAL | SQL_UNIQUE_LITERAL | SQL_NULL_LITERAL )
;

SQL_PRIMARY_KEY_LITERAL:
  'PRIMARY' 'KEY'
;

SQL_UNIQUE_LITERAL:
  'UNIQUE' 'KEY'
;

SQL_NULL_LITERAL:
  'NOT'? 'NULL'
;

/////////////////END SQL DDL//////////////////////////////////////////////////////////////////////

***** example CentroDeportivo en Athena, SQL, CQL y JSON/MongoDB *****

Schema CentroDeportivo:1

Root entity Instalacion
{
  +instalacion_id: Identifier,
  nombre: String,
  tipo: String in ("Interior", "Exterior"),
  m2: Double (1..9999999)
}

Root entity Monitor
{
  +dni: Identifier,
  nombre: String,
  telefono: Integer,
  fcontrato: Timestamp,
  salario: Double (0..999999),
  especialista: ref<Actividad>+
}

Root entity Actividad
{
  +actividad_id: Identifier,
  nombre: String,
  nivel: Integer (1..5),
  ?precio: Double (0..9999),
  responsable: Ref<Monitor>&,
  instalacion: Ref<Instalacion>&,
  sesiones: Aggr<Sesion>*
}

// Other form to define the relationship between Monitor and Actividad
//relationship Especialista
//{
//  monitor: Ref<Monitor>&,
//  actividad: Ref<Actividad>&
//}

entity Sesion
{
  diasemana: String in ("L", "M", "X", "J", "V", "S"),
  hora: Double,
  monitor: Ref<Monitor>&
}
*** SQL***

CREATE TABLE instalacion (
  instalacion_id CHAR(3)     NOT NULL,
  nombre         VARCHAR(30) NOT NULL,
  tipo           CHAR(8)     DEFAULT 'Interior' NOT NULL,
  m2             NUMBER(7,2) NOT NULL,
  CONSTRAINT instalacion_pk PRIMARY KEY(instalacion_id),
  CONSTRAINT tipo_check CHECK (tipo IN ('Interior', 'Exterior')),
  CONSTRAINT m2_check   CHECK (m2>0)
);

CREATE TABLE monitor (
  dni       CHAR(9)     NOT NULL,
  nombre    VARCHAR(30) NOT NULL,
  telefono  NUMBER(9)   NOT NULL,
  fcontrato DATE        NOT NULL,  
  salario   NUMBER(6,2) NOT NULL,
  CONSTRAINT monitor_pk PRIMARY KEY(dni),
  CONSTRAINT monitor_ak UNIQUE(telefono),
  CONSTRAINT salario_check CHECK (salario>0)
);

CREATE TABLE actividad (
  actividad_id   CHAR(3)     NOT NULL,
  nombre         VARCHAR(30) NOT NULL,
  nivel          CHAR(8)     DEFAULT 3 NOT NULL,
  precio         NUMBER(4,2) NULL,
  responsable    CHAR(9)     NOT NULL,
  instalacion_id CHAR(3)     NOT NULL,
  CONSTRAINT actividad_pk PRIMARY KEY(actividad_id),
  CONSTRAINT actividad_fk_monitor
    FOREIGN KEY(responsable)
    REFERENCES monitor(dni),
  CONSTRAINT actividad_fk_instalacion 
    FOREIGN KEY(instalacion_id)
    REFERENCES instalacion(instalacion_id),
  CONSTRAINT nivel_check  CHECK (nivel BETWEEN 1 AND 5),
  CONSTRAINT precio_check CHECK (precio IS NULL OR precio>=0)
);

CREATE TABLE especialista (
  monitor_id   CHAR(9)     NOT NULL,
  actividad_id CHAR(3)     NOT NULL,
  CONSTRAINT especialista_pk PRIMARY KEY(monitor_id, actividad_id),
  CONSTRAINT especialista_fk_monitor 
    FOREIGN KEY(monitor_id)
    REFERENCES monitor(dni),
  CONSTRAINT especialista_fk_actividad 
    FOREIGN KEY(actividad_id)
    REFERENCES actividad(actividad_id)
);

CREATE TABLE sesion (
  actividad_id CHAR(3)     NOT NULL,
  diasemana    CHAR(1)     NOT NULL,
  hora         NUMBER(4,2) NOT NULL,
  monitor_id   CHAR(9)     NOT NULL,
  CONSTRAINT sesion_pk PRIMARY KEY(actividad_id, diasemana, hora),
  CONSTRAINT sesion_fk_actividad 
    FOREIGN KEY(actividad_id)
    REFERENCES actividad(actividad_id),
  CONSTRAINT sesion_fk_monitor FOREIGN KEY(monitor_id)
    REFERENCES monitor(dni),
  CONSTRAINT diasemana_check  
    CHECK (diasemana IN ('L', 'M', 'X', 'J', 'V', 'S'))
);

*** CQL Cassandra ***

CREATE KEYSPACE CentroDeportivo 
WITH replication = { 'class': 'SimpleStrategy', 'replication_factor': 3 };


USE CentroDeportivo;

CREATE TABLE Instalacion (
    instalacion_id TEXT PRIMARY KEY,  
    nombre TEXT,
    tipo TEXT,
    m2 DOUBLE
);

CREATE TABLE monitor (
    dni TEXT PRIMARY KEY,
    nombre TEXT,
    telefono BIGINT,
    fcontrato TIMESTAMP,
    salario DOUBLE,
    especialista SET<TEXT>  
);

CREATE TABLE Actividad (
    actividad_id TEXT PRIMARY KEY, 
    nombre TEXT,
    nivel INT,
    precio DOUBLE,
    responsable TEXT, 
    instalacion_id TEXT
);

CREATE TABLE Sesion (
    actividad_id TEXT,
    diasemana TEXT,
    hora DOUBLE,
    monitor_id TEXT,
    PRIMARY KEY (actividad_id, diasemana, hora) 
);

*** JSON para MongoDB ****

use CentroDeportivo;

db.createCollection("Instalacion", {
  validator: {
    $jsonSchema: {
      bsonType: "object",
      required: ["instalacion_id", "nombre", "tipo", "m2"],
      properties: {
        instalacion_id: { bsonType: "string", description: "ID de la instalación, requerido y debe ser string." },
        nombre: { bsonType: "string", description: "Nombre de la instalación, requerido y debe ser string." },
        tipo: { enum: ["Interior", "Exterior"], description: "Tipo debe ser Interior o Exterior." },
        m2: { bsonType: "double", minimum: 1, maximum: 9999999, description: "Superficie en m2, debe estar entre 1 y 9999999." }
      }
    }
  }
});

db.Instalacion.createIndex({ instalacion_id: 1 }, { unique: true });

db.createCollection("Monitor", {
  validator: {
    $jsonSchema: {
      bsonType: "object",
      required: ["dni", "nombre", "telefono", "fcontrato", "salario", "especialista"],
      properties: {
        dni: { bsonType: "string", description: "DNI del monitor, requerido y debe ser string." },
        nombre: { bsonType: "string", description: "Nombre del monitor, requerido y debe ser string." },
        telefono: { bsonType: "int", minimum: 600000000, maximum: 999999999, description: "Teléfono debe ser un número entre 600000000 y 999999999." },
        fcontrato: { bsonType: "date", description: "Fecha de contrato, debe ser date." },
        salario: { bsonType: "double", minimum: 0, maximum: 999999, description: "Salario, debe estar entre 0 y 999999." },
        especialista: { bsonType: "array", items: { bsonType: "string" }, description: "Lista de IDs de actividades especializadas." }
      }
    }
  }
});

db.Monitor.createIndex({ dni: 1 }, { unique: true });

db.createCollection("Actividad", {
  validator: {
    $jsonSchema: {
      bsonType: "object",
      required: ["actividad_id", "nombre", "nivel", "responsable", "instalacion", "sesiones"],
      properties: {
        actividad_id: { bsonType: "string", description: "ID de la actividad, requerido y debe ser string." },
        nombre: { bsonType: "string", description: "Nombre de la actividad, requerido y debe ser string." },
        nivel: { bsonType: "int", minimum: 1, maximum: 5, description: "Nivel debe estar entre 1 y 5." },
        precio: { bsonType: "double", minimum: 0, maximum: 9999, description: "Precio opcional, entre 0 y 9999." },
        responsable: { bsonType: "string", description: "Referencia al monitor responsable." },
        instalacion: { bsonType: "string", description: "Referencia a la instalación donde se imparte la actividad." },
        sesiones: {
          bsonType: "array",
          items: {
            bsonType: "object",
            required: ["diasemana", "hora", "monitor"],
            properties: {
              diasemana: { enum: ["L", "M", "X", "J", "V", "S"], description: "Día de la semana debe ser un valor válido." },
              hora: { bsonType: "double", description: "Hora" },
              monitor: { bsonType: "string", description: "Referencia al monitor que imparte la sesión." }
            }
          },
          description: "Lista de sesiones de la actividad."
        }
      }
    }
  }
});

db.Actividad.createIndex({ actividad_id: 1 }, { unique: true });

***** example SoftwareDev en Athena, SQL, CQL y JSON/MongoDB *****

Schema SoftwareDev:1

FSet Popularity_features
{
  num_forks: Integer (0..1000),
  num_stars: Integer (0..1000)
}

FSet Timestamp_features
{
  created_time: Timestamp,
  last_activity_date:Timestamp
}

Root entity Developer
{
  Common
  {
    +id: Identifier,
    dev_info: Aggr<DeveloperInfo>&,
    !email: String /^.+@.+\\.com$/,
    permissions: String in ("R","W","X","RW","RX","WX","RWX")
  }
  Variation 1
  {
    is_active: Boolean
  }
  Variation 2
  {
    suspended_acc: Option<String, Boolean>
  }
}

Entity DeveloperInfo
{
  ?about_me: String,
  name: String /^[A-Z][a-z]*$/,
  team: String
}

Root entity Repository
{
  +id: Identifier,
  developers: Ref<Developer>+,
  requests: [{branch: String, status: String in ("Open", "Closed"), numLabels: Number}],
  ?tags: List<String>,
  title: String,
  url: String
}U Popularity_features
 U Timestamp_features

Root entity Ticket
  SQL CREATE TABLE Ticket(
    id VARCHAR(255)NOT NULL,
    message VARCHAR(255)NOT NULL,
    repository_id VARCHAR(255)NOT NULL,
    developer_id VARCHAR(255)NOT NULL,
    FOREIGN KEY (repository_id)
 REFERENCES Repository(id),
    FOREIGN KEY (developer_id)
 REFERENCES Developer (id),
    PRIMARY KEY (id)
  );
 +Popularity_features
 +Timestamp_features

*** SQL ***

CREATE TABLE Developer (
    id VARCHAR(255) NOT NULL,
    email VARCHAR(255) NOT NULL,
    permissions VARCHAR(3) NOT NULL,
    is_active BOOLEAN NULL,  
    suspended_acc VARCHAR(255) NULL,
    CONSTRAINT developer_pk PRIMARY KEY (id),
    CONSTRAINT email_check CHECK (email REGEXP '^.+@.+\\.com$'),
    CONSTRAINT permissions_check CHECK (permissions IN ('R', 'W', 'X', 'RW', 'RX', 'WX', 'RWX')),
    CONSTRAINT suspended_acc_check CHECK (suspended_acc IN ('true', 'false'))
);

CREATE TABLE DeveloperInfo (
    developer_id VARCHAR(255) NOT NULL,
    about_me VARCHAR(255) NULL,
    name VARCHAR(255) NOT NULL,
    team VARCHAR(255) NOT NULL,
    CONSTRAINT developer_info_pk PRIMARY KEY (developer_id),
    CONSTRAINT developer_info_fk_developer FOREIGN KEY (developer_id) REFERENCES Developer(id),
    CONSTRAINT name_check CHECK (name REGEXP '^[A-Z][a-z]*$')
);

CREATE TABLE Repository (
    id VARCHAR(255) NOT NULL,
    title VARCHAR(255) NOT NULL,
    url VARCHAR(255) NOT NULL,
    tags JSON DEFAULT NULL, 
    num_forks INT NOT NULL,
    num_stars INT NOT NULL,
    created_time TIMESTAMP NOT NULL,
    last_activity_date TIMESTAMP NOT NULL,
    CONSTRAINT repository_pk PRIMARY KEY (id),
    CONSTRAINT num_forks_check CHECK (num_forks BETWEEN 0 AND 1000),
    CONSTRAINT num_stars_check CHECK (num_stars BETWEEN 0 AND 1000)
);

CREATE TABLE Developer_Repository (
    developer_id VARCHAR(255) NOT NULL,
    repository_id VARCHAR(255) NOT NULL,
    CONSTRAINT developer_repository_pk PRIMARY KEY (developer_id, repository_id),
    CONSTRAINT developer_repository_fk_developer FOREIGN KEY (developer_id) REFERENCES Developer(id),
    CONSTRAINT developer_repository_fk_repository FOREIGN KEY (repository_id) REFERENCES Repository(id)
);

CREATE TABLE Requests (
    repository_id VARCHAR(255) NOT NULL,
    branch VARCHAR(255) NOT NULL,
    status ENUM('Open', 'Closed') NOT NULL,
    numLabels INT NOT NULL,
    CONSTRAINT requests_pk PRIMARY KEY (repository_id, branch),
    CONSTRAINT requests_fk_repository FOREIGN KEY (repository_id) REFERENCES Repository(id)
);

CREATE TABLE Ticket (
    id VARCHAR(255) NOT NULL,
    message VARCHAR(255) NOT NULL,
    repository_id VARCHAR(255) NOT NULL,
    developer_id VARCHAR(255) NOT NULL,
    num_forks INT NOT NULL,
    num_stars INT NOT NULL,
    created_time TIMESTAMP NOT NULL,
    last_activity_date TIMESTAMP NOT NULL,
    CONSTRAINT ticket_pk PRIMARY KEY (id),
    CONSTRAINT ticket_fk_repository FOREIGN KEY (repository_id) REFERENCES Repository(id),
    CONSTRAINT ticket_fk_developer FOREIGN KEY (developer_id) REFERENCES Developer(id),
    CONSTRAINT num_forks_check CHECK (num_forks BETWEEN 0 AND 1000),
    CONSTRAINT num_stars_check CHECK (num_stars BETWEEN 0 AND 1000)
);

***CQL Cassandra ****

CREATE KEYSPACE SoftwareDev 
WITH replication = {'class': 'SimpleStrategy', 'replication_factor': 3};

USE SoftwareDev;

CREATE TABLE Developer (
    id TEXT PRIMARY KEY,
    email TEXT,
    dev_info_name TEXT,
    dev_info_team TEXT,
    dev_info_about_me TEXT,
    permissions TEXT,
    is_active BOOLEAN,
    suspended_acc TEXT
);


CREATE TABLE Repository (
    id TEXT PRIMARY KEY,
    title TEXT,
    url TEXT,
    developers LIST<TEXT>,
    requests LIST<FROZEN<TUPLE<TEXT, TEXT, INT>>>,
    tags LIST<TEXT>,
    num_forks INT,
    num_stars INT,
    created_time TIMESTAMP,
    last_activity_date TIMESTAMP
);

CREATE TABLE Ticket (
    id TEXT PRIMARY KEY,
    message TEXT,
    repository_id TEXT,
    developer_id TEXT,
    num_forks INT,
    num_stars INT,
    created_time TIMESTAMP,
    last_activity_date TIMESTAMP
);

*** JSON para MongoDB *****

use SoftwareDev;

db.createCollection("Developer", {
  validator: {
    $jsonSchema: {
      bsonType: "object",
      required: ["id", "email", "permissions", "dev_info"],
      properties: {
        id: { bsonType: "string", description: "ID del Developer, debe ser string y es requerido." },
        dev_info: {
          bsonType: "object",
          required: ["name", "team"],
          properties: {
            about_me: { bsonType: "string", description: "Información opcional sobre el developer." },
            name: { bsonType: "string", pattern: "^[A-Z][a-z]*$", description: "Debe empezar con mayúscula." },
            team: { bsonType: "string", description: "Nombre del equipo al que pertenece el developer." }
          }
        },
        email: { bsonType: "string", pattern: "^.+@.+\\.com$", description: "Debe ser un email válido." },
        permissions: { enum: ["R", "W", "X", "RW", "RX", "WX", "RWX"], description: "Permisos válidos del developer." },
        is_active: { bsonType: "bool", description: "Indica si el usuario está activo." },
