parameters.jsCode:
let url = $json.file_url;

if (url.includes("github.com") && url.includes("/blob/")) {
  url = url
    .replace("github.com", "raw.githubusercontent.com")
    .replace("/blob/", "/");
}

return {
  ...$json,
  raw_url: url
};

return {
  id: $json.id,
  direction: $json.direction,
  file_url: $json.file_url,
  temperature: 0.7,
  run: 3,
  model: "GPT-5.4",
  raw_url: $json.raw_url,
  input: $json.data
};

let taskPrompt = "";
let direction = ($json.direction || "").trim();

switch (direction) {

  case "SQL_TO_ATHENA":
    taskPrompt = `
Convert the following SQL schema into Athena DSL.

Requirements:
- Use valid Athena syntax
- Preserve entities, attributes, keys, and relationships
- Ensure syntactic correctness

SQL input:
${$json.input}
`;
    break;

  case "CASSANDRA_TO_ATHENA":
    taskPrompt = `
Convert the following Cassandra (CQL) schema into Athena DSL.

Requirements:
- Use valid Athena syntax
- Preserve entities, attributes, and relationships
- Ensure syntactic correctness

Cassandra input:
${$json.input}
`;
    break;

  case "MongoDB_TO_ATHENA":
    taskPrompt = `
Convert the following MongoDB schema (with validator) into Athena DSL.

Requirements:
- Use valid Athena syntax
- Map document structure to entities and aggregates
- Preserve constraints where possible
- Ensure syntactic correctness

MongoDB input:
${$json.input}
`;
    break;

  case "NL_TO_ATHENA":
    taskPrompt = `
Convert the following natural language specification into Athena DSL.

Requirements:
- Use valid Athena syntax
- Infer entities, attributes, and relationships
- Ensure syntactic correctness

Specification:
${$json.input}
`;
    break;

  case "NL_TO_ALL":
    taskPrompt = `
Convert the following natural language specification into:

1. Athena DSL
2. SQL
3. Cassandra (CQL)
4. MongoDB with validator

Requirements:
- Ensure syntactic correctness in all outputs
- Preserve structure and constraints

Specification:
${$json.input}
`;
    break;

  case "ATHENA_TO_ALL":
    taskPrompt = `
Given the following Athena schema, convert it into:

1. SQL
2. Cassandra (CQL)
3. MongoDB with validator
4. Natural language description

Requirements:
- Preserve schema semantics
- Ensure syntactic correctness in all generated schemas

Athena input:
${$json.input}
`;
    break;

  default:
    taskPrompt = `
Unknown direction: ${direction}

Input:
${$json.input}
`;
}

return {
  ...$json,
  task_prompt: taskPrompt
};

const training = $("Build Full Prompt").first().json.training_prompt;

const finalPrompt = `
${training}

------------------------------------------------------------
TASK
------------------------------------------------------------

${$json.task_prompt}

------------------------------------------------------------
INSTRUCTIONS
------------------------------------------------------------

Use only the DSL knowledge from the training.
Provide only the final result.
Do not include explanations.
`;

return {
  ...$json,
  final_prompt: finalPrompt
};

// Obtener output (ajusta si cambia estructura)
let rawOutput = $json.output?.[0]?.content?.[0]?.text || "";

// 1. Eliminar ```plaintext, ```athena, etc.
let cleaned = rawOutput.replace(/```[a-zA-Z]*\n?/g, "");

// 2. Eliminar ``` restantes
cleaned = cleaned.replace(/```/g, "");

// 3. Trim espacios al inicio y final
cleaned = cleaned.trim();

// 4. (opcional pero recomendable) normalizar saltos de línea
cleaned = cleaned.replace(/\r\n/g, "\n");

// Devolver manteniendo todo lo demás
return {
  ...$json,
  output: cleaned
};
